import React, { useEffect, useState, useRef } from 'react';

// Utility to get current period index based on time
function getCurrentPeriod(date) {
  const hours = date.getHours();
  const minutes = date.getMinutes();
  const totalMinutes = hours * 60 + minutes;

  const periods = [
    [480, 530],   // 8:00 - 8:50
    [530, 580],   // 8:50 - 9:40
    [590, 640],   // 9:50 - 10:40
    [640, 690],   // 10:40 - 11:30
    [750, 800],   // 12:30 - 1:20
    [800, 850],   // 1:20 - 2:10
    [860, 910],   // 2:20 - 3:10
  ];

  for (let i = 0; i < periods.length; i++) {
    const [start, end] = periods[i];
    if (totalMinutes >= start && totalMinutes < end) {
      return i + 1; // Periods are 1-based
    }
  }

  return -1; // Not in any period (break/lunch/after school)
}

const Dashboard = () => {
  const [stats, setStats] = useState(null);
  const [selectedPeriod, setSelectedPeriod] = useState(null); // null = auto
  const prevPeriodRef = useRef(null);

  const fetchStats = async (period = null) => {
    const url = period !== null
      ? `/api/dashboard-stats?period=${period}`
      : `/api/dashboard-stats`;

    try {
      const res = await fetch(url);
      const data = await res.json();
      setStats(data);

      if (period === null && data.currentPeriod !== -1) {
        prevPeriodRef.current = data.currentPeriod;
      }
    } catch (err) {
      console.error("Error fetching stats:", err);
    }
  };

  // Initial load
  useEffect(() => {
    if (selectedPeriod !== null) {
      fetchStats(selectedPeriod);
    } else {
      fetchStats(); // Auto mode
    }
  }, [selectedPeriod]);

  // Period change auto-fetch logic
  useEffect(() => {
    let interval = null;

    if (selectedPeriod === null) {
      interval = setInterval(() => {
        const now = new Date();
        const currentPeriod = getCurrentPeriod(now);

        // Debug
        // console.log("Now:", now.toLocaleTimeString(), "| Period:", currentPeriod, "| Previous:", prevPeriodRef.current);

        if (currentPeriod !== -1 && currentPeriod !== prevPeriodRef.current) {
          fetchStats();
        }
      }, 60000); // Every 1 minute
    }

    return () => {
      if (interval) clearInterval(interval);
    };
  }, [selectedPeriod]);

  // Manual period change handler
  const handlePeriodChange = (e) => {
    const value = parseInt(e.target.value);
    setSelectedPeriod(isNaN(value) ? null : value);
  };

  // Get display time
  const currentTime = new Date().toLocaleTimeString();

  return (
    <div className="dashboard">
      <div className="time-bar">
        <span>🕒 {currentTime}</span>
        <span>
          {selectedPeriod === null
            ? `Auto Period: ${
                stats?.currentPeriod !== -1 ? `Period ${stats?.currentPeriod}` : "Break/Lunch"
              }`
            : `Manual Period: Period ${selectedPeriod}`}
        </span>
        <select onChange={handlePeriodChange} value={selectedPeriod ?? ''}>
          <option value="">Auto (Now)</option>
          <option value="1">Period 1 (8:00 - 8:50)</option>
          <option value="2">Period 2 (8:50 - 9:40)</option>
          <option value="3">Period 3 (9:50 - 10:40)</option>
          <option value="4">Period 4 (10:40 - 11:30)</option>
          <option value="5">Period 5 (12:30 - 1:20)</option>
          <option value="6">Period 6 (1:20 - 2:10)</option>
          <option value="7">Period 7 (2:20 - 3:10)</option>
        </select>
      </div>

      <div className="chart-section">
        {stats ? (
          <>
            {/* Render your charts here using stats */}
            {/* Example:
              <DonutChart title="Free vs Occupied" data={stats.classroomData} />
              <BarChart title="Free Rooms per Day" data={stats.weeklyData} />
            */}
          </>
        ) : (
          <p>Loading stats...</p>
        )}
      </div>
    </div>
  );
};

export default Dashboard;
